param([switch]$RunForever = $true)

# Load the bridge definitions (RawrXD_PatternBridge class and helpers)
# This file is generated by the build and contains the C# Add-Type definition
$sigFile = "D:\lazy init ide\bin\RawrXD_PatternBridge_Signatures.ps1"
if (-not (Test-Path $sigFile)) {
    throw "Signatures file not found: $sigFile"
}
. $sigFile | Out-Null

$pipeName = "RawrXD_PatternBridge_V2"

Write-Host "[IDE Bridge] Starting server on pipe: $pipeName" -ForegroundColor Green

while ($true) {
    try {
        $pipe = New-Object System.IO.Pipes.NamedPipeServerStream($pipeName, [System.IO.Pipes.PipeDirection]::InOut, 1, [System.IO.Pipes.PipeTransmissionMode]::Message)
        
        $pipe.WaitForConnection()
        
        $reader = New-Object System.IO.StreamReader($pipe)
        $writer = New-Object System.IO.StreamWriter($pipe)
        $writer.AutoFlush = $true
        
        $request = $reader.ReadLine()
        
        if ($request -match "^CLASSIFY\|(?<Path>.*)$") {
            $filePath = $matches['Path']
            if (Test-Path $filePath -PathType Leaf) {
                try {
                    $bytes = [System.IO.File]::ReadAllBytes($filePath)
                    $result = Invoke-RawrXDClassification -CodeBuffer $bytes
                    
                    # Map to the format client likely expects
                    $response = @{
                        Type = $result.TypeName
                        Confidence = $result.Confidence
                        LineNumber = 0 # Stub: The current bridge DLL stub doesn't do line analysis yet
                    }
                    $writer.WriteLine(($response | ConvertTo-Json -Compress))
                } catch {
                    $writer.WriteLine('{ "Error": "Processing Failed", "Message": "' + $_.Exception.Message + '" }')
                }
            } else {
                 $writer.WriteLine('{ "Error": "File not found" }')
            }
        } elseif ($request -eq "PING") {
            $writer.WriteLine("PONG")
        } elseif ($request -eq "SHUTDOWN") {
             $writer.WriteLine("BYE")
             $pipe.Disconnect()
             $pipe.Dispose()
             break
        }
        
        $pipe.Disconnect()
        $pipe.Dispose()
        
        if (-not $RunForever) { break }
        
    } catch {
        Write-Error "Server Error: $_"
        Start-Sleep -Seconds 1
    }
}
Write-Host "[IDE Bridge] Server stopped" -ForegroundColor Yellow
